function solve(s) {
    const seen = new Set();
    const result = [];
    let start = 0;
    while (start < s.length) {
        let current = '';
        for (let j = start; j < s.length; j++) {
            current += s[j];
            if (!seen.has(current)) {
                seen.add(current);
                result.push(current);
                start = j + 1;
                break;
            }
        }
    }
    return result;
}

